const BASE_COUNTS = (() => {
  const b = {};
  ZONES.forEach((z) => {
    const total = Math.floor(z.capacity * (0.45 + Math.random() * 0.35));
    const emp = Math.floor(total * 0.18);
    const contract = Math.floor(total * 0.32);
    const visitors = Math.floor(total * 0.26);
    const drivers = Math.max(0, total - emp - contract - visitors);
    b[z.id] = {
      total,
      emp,
      contract,
      visitors,
      drivers,
      sessionEntries: 0,
      sessionExits: 0,
      lastEvent: null,
    };
  });
  return b;
})();

function clamp(v, lo, hi) {
  return Math.min(hi, Math.max(lo, v));
}

function tickData(prev, tickCount) {
  const d = {};
  ZONES.forEach((z, zi) => {
    const p = prev?.[z.id] ?? BASE_COUNTS[z.id];
    const wave = Math.sin(((tickCount + zi * 9) / 72) * Math.PI * 2);
    const shouldMove = Math.random() < 1 / 12;
    let delta = 0;
    if (shouldMove) {
      if (wave > 0.2) delta = 1;
      else if (wave < -0.2) delta = -1;
      else delta = Math.random() < 0.5 ? 1 : -1;
    }
    const total = clamp(p.total + delta, 0, z.capacity);
    const emp = clamp(p.emp, 0, total);
    const contract = clamp(p.contract, 0, total - emp);
    const visitors = clamp(p.visitors, 0, total - emp - contract);
    const drivers = Math.max(0, total - emp - contract - visitors);
    const sessionEntries = (p.sessionEntries ?? 0) + (delta > 0 ? 1 : 0);
    const sessionExits = (p.sessionExits ?? 0) + (delta < 0 ? 1 : 0);
    const lastEvent = delta > 0 ? 'entry' : delta < 0 ? 'exit' : null;
    d[z.id] = {
      total,
      emp,
      contract,
      visitors,
      drivers,
      sessionEntries,
      sessionExits,
      lastEvent,
    };
  });
  return d;
}

function initData() {
  const d = {};
  ZONES.forEach((z) => {
    d[z.id] = { ...BASE_COUNTS[z.id] };
  });
  return d;
}

