const MASTER_ROSTER = (() => {
  const roster = [];
  let pidx = 0;
  ZONES.forEach((z) => {
    const count = Math.floor(z.capacity * (0.45 + Math.random() * 0.35));
    for (let i = 0; i < count; i++) {
      const name = PERSON_NAMES[pidx % PERSON_NAMES.length];
      pidx++;
      const role = ROLES[Math.floor(Math.random() * ROLES.length)];
      const prefix = BADGE_POOL[ROLES.indexOf(role)];
      const badge =
        prefix +
        String(1000 + pidx * 7 + Math.floor(Math.random() * 99)).slice(-4);
      roster.push({
        id: pidx,
        name,
        role,
        badge,
        zoneId: z.id,
        present: true,
        entryTime: (() => {
          const d = new Date();
          d.setMinutes(d.getMinutes() - Math.floor(Math.random() * 120));
          return d;
        })(),
      });
    }
  });
  return roster;
})();

let _nameIdx = MASTER_ROSTER.length;
function nextPerson() {
  const idx = _nameIdx % PERSON_NAMES.length;
  _nameIdx++;
  const role = ROLES[Math.floor(Math.random() * ROLES.length)];
  const prefix = BADGE_POOL[ROLES.indexOf(role)];
  const badge =
    prefix + String(1000 + Math.floor(Math.random() * 9000)).slice(0, 4);
  return { name: PERSON_NAMES[idx], role, badge };
}

function getStatus(total, capacity) {
  const p = total / capacity;
  if (total === 0)
    return { label: 'EMPTY', color: '#555', bg: '#222', border: '#333' };
  if (p < 0.4)
    return {
      label: 'SAFE',
      color: '#00e676',
      bg: '#0a2e1a',
      border: '#00e676',
    };
  if (p < 0.65)
    return {
      label: 'MEDIUM',
      color: '#ffd600',
      bg: '#2a2200',
      border: '#ffd600',
    };
  if (p < 0.85)
    return {
      label: 'HIGH',
      color: '#ff6d00',
      bg: '#2a1500',
      border: '#ff6d00',
    };
  return {
    label: 'CRITICAL',
    color: '#f44336',
    bg: '#2a0000',
    border: '#f44336',
  };
}

function getTileColor(total, capacity, baseColor) {
  const p = total / capacity;
  if (total === 0) return '#1e1e1e';
  if (p < 0.4) return '#1e4a28';
  if (p < 0.65) return baseColor;
  if (p < 0.85) return '#8b3a00';
  return '#8b1a1a';
}

