function ZoneTile({
  zone,
  personnel,
  isSelected,
  onClick,
  emergencyMode,
  evacuated,
}) {
  const T = useTheme();
  const total = personnel?.total ?? 0;
  const entries = personnel?.sessionEntries ?? 0;
  const exits = personnel?.sessionExits ?? 0;
  const lastEvt = personnel?.lastEvent;
  const status = getStatus(total, zone.capacity);
  const tileColor = emergencyMode
    ? evacuated
      ? '#0a2e1a'
      : total > 0
      ? '#2a0a0a'
      : '#111'
    : getTileColor(total, zone.capacity, zone.baseColor);
  const pct = Math.min(total / zone.capacity, 1);
  const [hov, setHov] = useState(false);
  const [flash, setFlash] = useState(null);

  useEffect(() => {
    if (!lastEvt) return;
    setFlash(lastEvt);
    const t = setTimeout(() => setFlash(null), 900);
    return () => clearTimeout(t);
  }, [entries, exits]);

  return (
    <div
      onClick={() => onClick(zone.id)}
      onMouseEnter={() => setHov(true)}
      onMouseLeave={() => setHov(false)}
      style={{
        background: tileColor,
        border: isSelected
          ? `2px solid ${status.color}`
          : hov
          ? `1.5px solid ${status.color}88`
          : '1.5px solid rgba(255,255,255,0.08)',
        borderRadius: 8,
        padding: '10px 10px 8px',
        cursor: 'pointer',
        position: 'relative',
        transition: 'all 0.18s',
        boxShadow: isSelected
          ? `0 0 18px ${status.color}44`
          : hov
          ? `0 0 10px ${status.color}22`
          : 'none',
        minHeight: 120,
        display: 'flex',
        flexDirection: 'column',
        justifyContent: 'space-between',
        overflow: 'hidden',
      }}
    >
      {flash && (
        <div
          style={{
            position: 'absolute',
            inset: 0,
            borderRadius: 7,
            pointerEvents: 'none',
            zIndex: 10,
            background:
              flash === 'entry'
                ? 'rgba(0,230,118,0.13)'
                : 'rgba(244,67,54,0.13)',
            border: `1.5px solid ${flash === 'entry' ? '#00e676' : '#f44336'}`,
            animation: 'flashFade 0.9s ease forwards',
          }}
        />
      )}
      <div
        style={{
          display: 'flex',
          justifyContent: 'space-between',
          alignItems: 'center',
        }}
      >
        <div style={{ display: 'flex', alignItems: 'center', gap: 4 }}>
          <div
            style={{
              width: 6,
              height: 6,
              borderRadius: '50%',
              background: status.color,
              boxShadow: `0 0 5px ${status.color}`,
            }}
          />
          <span
            style={{
              fontSize: 8,
              color: 'rgba(255,255,255,0.55)',
              fontFamily: 'monospace',
              letterSpacing: 1.5,
            }}
          >
            {zone.short}
          </span>
        </div>
        <div
          style={{
            width: 6,
            height: 6,
            borderRadius: '50%',
            border: `1.5px solid ${status.color}66`,
          }}
        />
      </div>
      <div style={{ textAlign: 'center' }}>
        <div
          style={{
            fontSize: 28,
            fontWeight: 900,
            color: 'rgba(255,255,255,0.95)',
            fontFamily: 'monospace',
            lineHeight: 1,
          }}
        >
          {emergencyMode && evacuated ? '✓' : total}
        </div>
        <div
          style={{
            fontSize: 7.5,
            color: 'rgba(255,255,255,0.35)',
            fontFamily: 'monospace',
            marginTop: 1,
          }}
        >
          {total} / {zone.capacity}
        </div>
      </div>
      <div
        style={{
          display: 'flex',
          justifyContent: 'space-between',
          gap: 4,
          background: 'rgba(0,0,0,0.25)',
          borderRadius: 5,
          padding: '4px 6px',
        }}
      >
        <div style={{ display: 'flex', alignItems: 'center', gap: 3 }}>
          <div
            style={{
              fontSize: 7,
              fontWeight: 800,
              color: '#00e676',
              fontFamily: 'monospace',
              background: 'rgba(0,230,118,0.12)',
              borderRadius: 3,
              padding: '1px 5px',
              border: '1px solid rgba(0,230,118,0.25)',
              letterSpacing: 0.5,
              boxShadow: flash === 'entry' ? '0 0 8px #00e676' : 'none',
              transition: 'box-shadow 0.3s',
            }}
          >
            IN
          </div>
          <span
            style={{
              fontSize: 10,
              fontWeight: 800,
              color: '#00e676',
              fontFamily: 'monospace',
            }}
          >
            {entries}
          </span>
        </div>
        <div style={{ width: 1, background: 'rgba(255,255,255,0.1)' }} />
        <div style={{ display: 'flex', alignItems: 'center', gap: 3 }}>
          <span
            style={{
              fontSize: 10,
              fontWeight: 800,
              color: '#f44336',
              fontFamily: 'monospace',
            }}
          >
            {exits}
          </span>
          <div
            style={{
              fontSize: 7,
              fontWeight: 800,
              color: '#f44336',
              fontFamily: 'monospace',
              background: 'rgba(244,67,54,0.12)',
              borderRadius: 3,
              padding: '1px 5px',
              border: '1px solid rgba(244,67,54,0.25)',
              letterSpacing: 0.5,
              boxShadow: flash === 'exit' ? '0 0 8px #f44336' : 'none',
              transition: 'box-shadow 0.3s',
            }}
          >
            OUT
          </div>
        </div>
      </div>
      <div
        style={{
          height: 3,
          background: 'rgba(0,0,0,0.3)',
          borderRadius: 2,
          overflow: 'hidden',
        }}
      >
        <div
          style={{
            width: `${pct * 100}%`,
            height: '100%',
            background: status.color,
            borderRadius: 2,
            transition: 'width 0.5s',
          }}
        />
      </div>
    </div>
  );
}

